## Issues and Improvements

### 1. **No Error Handling (Critical Bug)**
The function fails silently if any request fails. A single failed request will break the entire operation.

**Fix:**
```javascript
async function fetchAll(urls) {
  const results = [];
  for (const url of urls) {
    try {
      const res = await fetch(url);
      if (!res.ok) {
        throw new Error(`HTTP ${res.status} for ${url}`);
      }
      results.push(await res.json());
    } catch (error) {
      // Handle error - could log, push error object, or rethrow
      console.error(`Failed to fetch ${url}:`, error);
      results.push({ error: error.message, url });
    }
  }
  return results;
}
```

### 2. **Sequential Execution (Performance Issue)**
Requests run sequentially (`await` in loop), causing unnecessary delays. For independent URLs, parallel execution is better.

**Fix for parallel execution:**
```javascript
async function fetchAll(urls) {
  const promises = urls.map(async (url) => {
    try {
      const res = await fetch(url);
      if (!res.ok) {
        throw new Error(`HTTP ${res.status} for ${url}`);
      }
      return await res.json();
    } catch (error) {
      console.error(`Failed to fetch ${url}:`, error);
      return { error: error.message, url };
    }
  });

  return Promise.all(promises);
}
```

### 3. **No Input Validation (Security/Reliability)**
- No check if `urls` is an array
- No URL validation/sanitization

**Fix:**
```javascript
async function fetchAll(urls) {
  if (!Array.isArray(urls)) {
    throw new TypeError('urls must be an array');
  }

  // Optional: Validate URLs
  const isValidUrl = (url) => {
    try {
      new URL(url);
      return true;
    } catch {
      return false;
    }
  };

  const promises = urls.map(async (url, index) => {
    if (!isValidUrl(url)) {
      return { error: `Invalid URL at index ${index}: ${url}` };
    }

    try {
      const res = await fetch(url);
      if (!res.ok) {
        throw new Error(`HTTP ${res.status} for ${url}`);
      }
      return await res.json();
    } catch (error) {
      console.error(`Failed to fetch ${url}:`, error);
      return { error: error.message, url };
    }
  });

  return Promise.all(promises);
}
```

### 4. **No Timeout Handling (Reliability Issue)**
Requests could hang indefinitely.

**Fix:**
```javascript
async function fetchWithTimeout(url, timeout = 10000) {
  const controller = new AbortController();
  const timeoutId = setTimeout(() => controller.abort(), timeout);

  try {
    const res = await fetch(url, { signal: controller.signal });
    clearTimeout(timeoutId);
    return res;
  } catch (error) {
    clearTimeout(timeoutId);
    throw error;
  }
}

